    logger.warn("effect buffer full")
}

private val _effects = MutableSharedFlow<UiEffect>(
    replay = 0,
    extraBufferCapacity = 1
)
val effects: SharedFlow<UiEffect> = _effects.asSharedFlow()

fun onSaved() {
    _effects.tryEmit(UiEffect.ShowSnackbar("Saved"))
}

class ChatSession(
    socket: ChatSocket,
    sessionScope: CoroutineScope
) {
    private val upstream: Flow<SocketEvent> = callbackFlow {
        val listener = socket.listen { event -> trySend(event) }
        socket.connect()
        awaitClose {
            listener.dispose()
            socket.disconnect()
        }
    }

    val events: SharedFlow<SocketEvent> = upstream.shareIn(
        scope = sessionScope,
        started = SharingStarted.Eagerly,
        replay = 0
    )
}

@Test
fun newSubscriberReceivesReplay() = runTest {
    val flow = MutableSharedFlow<Int>(replay = 1)
    flow.emit(1)
    flow.emit(2)

    assertEquals(2, flow.first())
}
